import "./tabs.css";

import { Tabs } from "radix-ui";
import { cn } from "tailwind-variants";

import { TabsContext } from "./tabs.context";
import { tabsVariants } from "./tabs.variants";

export type TabsRootProps = React.ComponentProps<typeof Tabs.Root>;

export const TabsRoot = ({ className, ...props }: TabsRootProps) => {
  const slots = tabsVariants();

  return (
    <TabsContext value={{ slots }}>
      <Tabs.Root className={cn(slots.root(), className)} {...props} />
    </TabsContext>
  );
};

import { Tabs } from "radix-ui";
import { cn } from "tailwind-variants";

import { useTabsContext } from "./tabs.context";

export type TabsListProps = React.ComponentProps<typeof Tabs.List>;

export const TabsList = ({ className, ...props }: TabsListProps) => {
  const { slots } = useTabsContext();

  return <Tabs.List className={cn(slots.list(), className)} {...props} />;
};

import { Tabs } from "radix-ui";
import { cn } from "tailwind-variants";

import { useTabsContext } from "./tabs.context";

export type TabsTriggerProps = React.ComponentProps<typeof Tabs.Trigger>;

export const TabsTrigger = ({ className, ...props }: TabsTriggerProps) => {
  const { slots } = useTabsContext();

  return <Tabs.Trigger className={cn(slots.trigger(), className)} {...props} />;
};

import { Tabs } from "radix-ui";
import { cn } from "tailwind-variants";

import { useTabsContext } from "./tabs.context";

export type TabsContentProps = React.ComponentProps<typeof Tabs.Content>;

export const TabsContent = ({ className, ...props }: TabsContentProps) => {
  const { slots } = useTabsContext();

  return <Tabs.Content className={cn(slots.content(), className)} {...props} />;
};

import { createContext, useContext } from "react";

import { tabsVariants } from "./tabs.variants";

export type TabsContext = {
  slots: ReturnType<typeof tabsVariants>;
};

export const TabsContext = createContext<null | TabsContext>(null);

export const useTabsContext = () => {
  const context = useContext(TabsContext);
  if (!context) {
    throw new Error("useTabsContext must be used within Tabs");
  }
  return context;
};

import { tv, type VariantProps } from "tailwind-variants";

export const tabsVariants = tv({
  slots: {
    content: "tabs__content",
    list: "tabs__list",
    root: "tabs",
    trigger: "tabs__trigger",
  },
});

export type TabsVariants = VariantProps<typeof tabsVariants>;

.tabs {
  @apply w-full;
}

.tabs__list {
  @apply bg-muted text-muted-foreground inline-flex h-9 w-full items-center justify-center rounded-lg p-1;
}

.tabs__trigger {
  @apply ring-offset-background inline-flex flex-1 items-center justify-center rounded-md px-3 py-1 text-sm font-medium whitespace-nowrap transition-all;

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &:disabled {
    @apply pointer-events-none opacity-50;
  }

  &[data-state="active"] {
    @apply bg-background text-foreground shadow;
  }
}

.tabs__content {
  @apply ring-offset-background mt-2;

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }
}

import { TabsContent } from "./tabs-content";
import { TabsList } from "./tabs-list";
import { TabsRoot } from "./tabs-root";
import { TabsTrigger } from "./tabs-trigger";

export const Tabs = {
  Content: TabsContent,
  List: TabsList,
  Root: TabsRoot,
  Trigger: TabsTrigger,
};

export { TabsContent, TabsList, TabsRoot, TabsTrigger };

export type { TabsContentProps } from "./tabs-content";

export type { TabsListProps } from "./tabs-list";

export type { TabsRootProps } from "./tabs-root";
export type { TabsTriggerProps } from "./tabs-trigger";
export { TabsContext, useTabsContext } from "./tabs.context";
export { type TabsVariants, tabsVariants } from "./tabs.variants";
